#!/usr/bin/env bash
set -euo pipefail

# CocoaPods header symlinks are normally generated by `pod install` under:
#   ios/Pods/Headers/Public/<PodName>
#
# On this machine, CocoaPods currently can't regenerate Pods (Xcode objectVersion 70),
# but Xcode builds can fail if module map files are missing from those expected paths.
#
# This script reconstructs the minimal public header layout for any pod that has a
# module map in `ios/Pods/Target Support Files/<PodName>/`.

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
cd "$ROOT_DIR"

TARGET_SUPPORT_DIR="ios/Pods/Target Support Files"
PUBLIC_HEADERS_DIR="ios/Pods/Headers/Public"

mkdir -p "$PUBLIC_HEADERS_DIR"

warns=0
pods=0

while IFS= read -r mm; do
  [[ -z "$mm" ]] && continue
  pod="$(basename "$(dirname "$mm")")"
  xcconfig_debug="$TARGET_SUPPORT_DIR/$pod/${pod}.debug.xcconfig"
  xcconfig_release="$TARGET_SUPPORT_DIR/$pod/${pod}.release.xcconfig"
  xcconfig=""
  if [[ -f "$xcconfig_debug" ]]; then
    xcconfig="$xcconfig_debug"
  elif [[ -f "$xcconfig_release" ]]; then
    xcconfig="$xcconfig_release"
  fi

  # Prefer searching headers within this pod's source root; many pods are sourced from node_modules
  # and do not live under ios/Pods/<PodName>.
  pod_srcroot=""
  if [[ -n "$xcconfig" ]]; then
    pod_srcroot="$(ROOT_DIR="$ROOT_DIR" XCCONFIG="$xcconfig" python3 - <<'PY'
import os

root = os.path.abspath(os.environ["ROOT_DIR"])
xcconfig = os.environ["XCCONFIG"]

val = ""
try:
    with open(xcconfig, "r", encoding="utf-8") as f:
        for line in f:
            if line.startswith("PODS_TARGET_SRCROOT"):
                _, rhs = line.split("=", 1)
                val = rhs.strip().strip('"')
                break
except FileNotFoundError:
    val = ""

if val:
    val = val.replace("${PODS_ROOT}", "ios/Pods").replace("$(PODS_ROOT)", "ios/Pods")
    val = val.replace("${SRCROOT}", "ios/Pods").replace("$(SRCROOT)", "ios/Pods")
    abs_path = os.path.normpath(os.path.join(root, val))
    if os.path.isdir(abs_path) or os.path.isfile(abs_path):
        print(abs_path)
PY
)"
  fi

  dest_dir="$PUBLIC_HEADERS_DIR/$pod"
  mkdir -p "$dest_dir"

  base_mm="$(basename "$mm")"
  cp -f "$mm" "$dest_dir/$base_mm"

  umbrella_src="$TARGET_SUPPORT_DIR/$pod/${pod}-umbrella.h"
  if [[ -f "$umbrella_src" ]]; then
    cp -f "$umbrella_src" "$dest_dir/${pod}-umbrella.h"

    # Symlink each header referenced by the umbrella header into this folder.
    # CocoaPods normally flattens these; we do the same for just the headers that
    # the module map's umbrella header pulls in.
    while IFS= read -r header; do
      [[ -z "$header" ]] && continue
      dest_path="$dest_dir/$header"

      # If umbrella references a nested path (e.g. ExpoModulesCore/EXDefines.h),
      # create that directory structure under Headers/Public/<PodName>/.
      if [[ "$header" == */* ]]; then
        mkdir -p "$(dirname "$dest_path")"
      fi

      # Prefer headers that belong to the pod's source directory.
      src=""
      if [[ "$header" == */* ]]; then
        if [[ -n "$pod_srcroot" ]]; then
          src="$(find "$pod_srcroot" -path "*/$header" -type f 2>/dev/null | head -n 1 || true)"
        fi
        if [[ -z "$src" ]]; then
          src="$(find "ios/Pods/$pod" -path "*/$header" -type f 2>/dev/null | head -n 1 || true)"
        fi
      fi
      if [[ -z "$src" ]]; then
        if [[ -n "$pod_srcroot" ]]; then
          src="$(find "$pod_srcroot" -name "$(basename "$header")" -type f 2>/dev/null | head -n 1 || true)"
        fi
        if [[ -z "$src" ]]; then
          src="$(find "ios/Pods/$pod" -name "$(basename "$header")" -type f 2>/dev/null | head -n 1 || true)"
        fi
      fi

      # Some pods don't keep headers under `ios/Pods/<PodName>`; fall back to any pod path.
      if [[ -z "$src" ]]; then
        if [[ "$header" == */* ]]; then
          src="$(find ios -path "*/$pod/*" -path "*/$header" -type f 2>/dev/null | head -n 1 || true)"
        fi
      fi
      if [[ -z "$src" ]]; then
        src="$(find ios -path "*/$pod/*" -name "$(basename "$header")" -type f 2>/dev/null | head -n 1 || true)"
      fi
      if [[ -z "$src" ]]; then
        if [[ "$header" == */* ]]; then
          src="$(find ios -path "*/$header" -type f 2>/dev/null | head -n 1 || true)"
        fi
      fi
      if [[ -z "$src" ]]; then
        src="$(find ios -name "$(basename "$header")" -type f 2>/dev/null | head -n 1 || true)"
      fi

      if [[ -z "$src" ]]; then
        echo "WARN: $pod: header not found: $header" >&2
        warns=$((warns + 1))
        continue
      fi

      # Use absolute->relative path conversion to safely handle nested header paths.
      rel="$(python3 - <<PY
import os
root=os.path.abspath("$ROOT_DIR")
src="$src"
if not os.path.isabs(src):
    src=os.path.join(root, src)
dst=os.path.join(root, "$dest_path")
print(os.path.relpath(src, os.path.dirname(dst)))
PY
)"
      ln -sf "$rel" "$dest_path"
    done < <(awk -F\" '/^#import \".*\.h\"/{print $2}' "$dest_dir/${pod}-umbrella.h" | sort -u)
  fi
  pods=$((pods + 1))
done < <(find "$TARGET_SUPPORT_DIR" -maxdepth 2 -name '*.modulemap' | sort)

if [[ $pods -eq 0 ]]; then
  echo "No modulemaps found under $TARGET_SUPPORT_DIR" >&2
  exit 1
fi

echo "Repaired public header modulemaps for $pods pods."
if [[ $warns -ne 0 ]]; then
  echo "Completed with $warns warnings (missing headers)."
fi
